// Calculate Advanced Risk Metrics from Merged Financial Data
// This code processes risk and claims data to compute volatility, concentration indices, and trend analysis

const items = $input.all();

// Initialize aggregated metrics
let totalExposure = 0;
let totalClaims = 0;
let claimsHistory = [];
let exposureByGeography = {};
let exposureByIndustry = {};
let exposureByCounterparty = {};

// Process each item to extract risk and claims data
for (const item of items) {
  const data = item.json;

  // Aggregate exposure data
  if (data.exposure) {
    totalExposure += data.exposure.amount || 0;

    // Geographic concentration
    const geo = data.exposure.geography || 'Unknown';
    exposureByGeography[geo] = (exposureByGeography[geo] || 0) + (data.exposure.amount || 0);

    // Industry concentration
    const industry = data.exposure.industry || 'Unknown';
    exposureByIndustry[industry] = (exposureByIndustry[industry] || 0) + (data.exposure.amount || 0);

    // Counterparty concentration
    const counterparty = data.exposure.counterparty || 'Unknown';
    exposureByCounterparty[counterparty] = (exposureByCounterparty[counterparty] || 0) + (data.exposure.amount || 0);
  }

  // Aggregate claims data
  if (data.claims) {
    totalClaims += data.claims.amount || 0;
    claimsHistory.push({
      date: data.claims.date || new Date().toISOString(),
      amount: data.claims.amount || 0,
      severity: data.claims.severity || 'Unknown'
    });
  }
}

// Calculate concentration indices (Herfindahl-Hirschman Index)
const calculateHHI = (distribution, total) => {
  let hhi = 0;
  for (const key in distribution) {
    const share = distribution[key] / total;
    hhi += share * share;
  }
  return hhi * 10000; // Scale to 0-10000
};

const geoConcentrationIndex = calculateHHI(exposureByGeography, totalExposure);
const industryConcentrationIndex = calculateHHI(exposureByIndustry, totalExposure);
const counterpartyConcentrationIndex = calculateHHI(exposureByCounterparty, totalExposure);

// Calculate claims volatility (standard deviation)
const calculateVolatility = (values) => {
  if (values.length === 0) return 0;
  const mean = values.reduce((sum, val) => sum + val, 0) / values.length;
  const variance = values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / values.length;
  return Math.sqrt(variance);
};

const claimsAmounts = claimsHistory.map(c => c.amount);
const claimsVolatility = calculateVolatility(claimsAmounts);

// Calculate loss ratio
const lossRatio = totalExposure > 0 ? (totalClaims / totalExposure) * 100 : 0;

// Trend analysis - calculate moving average and trend direction
const calculateTrend = (values) => {
  if (values.length < 2) return 'Stable';
  const recentAvg = values.slice(-3).reduce((sum, val) => sum + val, 0) / Math.min(3, values.length);
  const olderAvg = values.slice(0, -3).reduce((sum, val) => sum + val, 0) / Math.max(1, values.length - 3);

  if (recentAvg > olderAvg * 1.1) return 'Increasing';
  if (recentAvg < olderAvg * 0.9) return 'Decreasing';
  return 'Stable';
};

const claimsTrend = calculateTrend(claimsAmounts);

// Calculate frequency metrics
const claimsFrequency = claimsHistory.length;
const avgClaimSeverity = claimsAmounts.length > 0 ? claimsAmounts.reduce((sum, val) => sum + val, 0) / claimsAmounts.length : 0;

// Determine top concentrations
const getTopConcentrations = (distribution, total, limit = 3) => {
  return Object.entries(distribution)
    .map(([key, value]) => ({ name: key, amount: value, percentage: (value / total * 100).toFixed(2) }))
    .sort((a, b) => b.amount - a.amount)
    .slice(0, limit);
};

const topGeographies = getTopConcentrations(exposureByGeography, totalExposure);
const topIndustries = getTopConcentrations(exposureByIndustry, totalExposure);
const topCounterparties = getTopConcentrations(exposureByCounterparty, totalExposure);

// Return comprehensive risk metrics
return [{
  json: {
    riskMetrics: {
      totalExposure,
      totalClaims,
      lossRatio: lossRatio.toFixed(2),
      claimsVolatility: claimsVolatility.toFixed(2),
      claimsFrequency,
      avgClaimSeverity: avgClaimSeverity.toFixed(2),
      claimsTrend
    },
    concentrationIndices: {
      geographic: geoConcentrationIndex.toFixed(2),
      industry: industryConcentrationIndex.toFixed(2),
      counterparty: counterpartyConcentrationIndex.toFixed(2)
    },
    topConcentrations: {
      geographies: topGeographies,
      industries: topIndustries,
      counterparties: topCounterparties
    },
    claimsHistory,
    timestamp: new Date().toISOString()
  }
}];

