// Generate comprehensive audit metadata for compliance tracking
const workflowId = $workflow.id;
const executionId = $execution.id;
const executionMode = $execution.mode;
const timestamp = new Date().toISOString();

// Get input data from Compliance Orchestration Agent
const complianceData = $input.all();

// Extract risk assessment data from the workflow
const riskAssessment = $('Risk Signal Agent').first().json;

// Generate data lineage tracking
const dataLineage = {
  sourceNodes: [
    'Fetch Risk Data',
    'Fetch Claims Data',
    'Merge Financial Data',
    'Risk Signal Agent',
    'Compliance Orchestration Agent'
  ],
  processingSteps: [
    {
      step: 1,
      node: 'Fetch Risk Data',
      timestamp: timestamp,
      action: 'Retrieved risk and exposure data from external API'
    },
    {
      step: 2,
      node: 'Fetch Claims Data',
      timestamp: timestamp,
      action: 'Retrieved claims history data from external API'
    },
    {
      step: 3,
      node: 'Merge Financial Data',
      timestamp: timestamp,
      action: 'Combined risk and claims datasets'
    },
    {
      step: 4,
      node: 'Risk Signal Agent',
      timestamp: timestamp,
      action: 'AI-powered risk assessment and scoring'
    },
    {
      step: 5,
      node: 'Compliance Orchestration Agent',
      timestamp: timestamp,
      action: 'Compliance workflow coordination and audit packaging'
    }
  ]
};

// Generate compliance checksums for data integrity
const generateChecksum = (data) => {
  const str = JSON.stringify(data);
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16);
};

const checksums = {
  riskAssessment: generateChecksum(riskAssessment),
  complianceData: generateChecksum(complianceData),
  combined: generateChecksum({ riskAssessment, complianceData })
};

// User context and system information
const userContext = {
  workflowName: $workflow.name,
  workflowActive: $workflow.active,
  executionMode: executionMode,
  triggeredBy: 'Schedule Trigger',
  n8nVersion: $version || 'unknown'
};

// Compliance metadata
const complianceMetadata = {
  auditId: `AUDIT-${executionId}-${Date.now()}`,
  workflowExecutionId: executionId,
  workflowId: workflowId,
  executionTimestamp: timestamp,
  processingDate: new Date().toISOString().split('T')[0],
  processingTime: new Date().toISOString().split('T')[1],
  dataLineage: dataLineage,
  checksums: checksums,
  userContext: userContext,
  riskScore: riskAssessment?.riskScore || null,
  riskLevel: riskAssessment?.riskLevel || null,
  complianceStatus: complianceData[0]?.json?.auditPackage?.documentationComplete ? 'Complete' : 'Incomplete',
  retentionPolicy: '7 years',
  regulatoryFrameworks: complianceData[0]?.json?.regulatoryItems?.map(item => item.framework) || [],
  auditTrailComplete: true,
  dataIntegrityVerified: true,
  version: '1.0'
};

// Return enriched data with audit metadata
return complianceData.map(item => ({
  json: {
    ...item.json,
    auditMetadata: complianceMetadata
  }
}));
